\end{center}

\vspace{1mm}
\begin{tcolorbox}[colback=zfgray, colframe=zfgreen!60, boxrule=0.5pt, arc=2pt, left=6pt, right=6pt, top=4pt, bottom=4pt]
\textbf{Pamatuj:} \quad 1 m/s = 3,6 km/h \quad $|$ \quad 36 km/h = 10 m/s
\end{tcolorbox}

\vspace{3mm}
{\Large \bfseries \color{zfblue} Příklady rychlostí}
\vspace{2mm}

\begin{center}
\renewcommand{\arraystretch}{1.3}
\setlength{\tabcolsep}{8pt}
\begin{tabular}{|l|c|c|}
\hline
\rowcolor{zfblue!25}
\bfseries Pohyb & \bfseries m/s & \bfseries km/h \\
\hline
chodec & 1,5 & 5 \\
cyklista & 5 & 18 \\
auto ve městě & 14 & 50 \\
auto na dálnici & 36 & 130 \\
zvuk ve vzduchu & 340 & 1\,224 \\
letadlo & 250 & 900 \\
světlo ve vakuu & 300\,000\,000 & 1\,080\,000\,000 \\
\hline
\end{tabular}
\end{center}

\vspace{3mm}
{\Large \bfseries \color{zfblue} Příklady výpočtu}
\vspace{2mm}

\noindent
\textbf{1)} Cyklista ujel 36 km za 2 hodiny. Jaká je jeho rychlost?
\vspace{1mm}

\noindent
\quad $v = \dfrac{s}{t} = \dfrac{36~\text{km}}{2~\text{h}} = 18~\text{km/h}$ \quad (= 5 m/s)

\vspace{3mm}
\noindent
\textbf{2)} Auto jede stálou rychlostí 90 km/h. Kolik ujede za 3 hodiny?
\vspace{1mm}

\noindent
\quad $s = v \cdot t = 90 \cdot 3 = 270~\text{km}$

\vspace{3mm}
\noindent
\textbf{3)} Vlak jede z Prahy do Brna (200 km) rychlostí 100 km/h. Jak dlouho cesta trvá?
\vspace{1mm}

\noindent
\quad $t = \dfrac{s}{v} = \dfrac{200~\text{km}}{100~\text{km/h}} = 2~\text{h}$

\vspace{3mm}
{\Large \bfseries \color{zfblue} Průměrná rychlost}
\vspace{2mm}

\begin{itemize}
    \item U nerovnoměrného pohybu (zrychlujeme, zpomalujeme, stojíme) počítáme \textbf{průměrnou rychlost}.
    \item Vzorec je stejný: $v_p = \dfrac{\text{celá dráha}}{\text{celý čas}}$.
\end{itemize}

